Allow constant time look-up whether a piece exists with the given int for each int in the arr using a Map where we bind each piece to its begining.

```
class Solution {
    public boolean canFormArray(int[] arr, int[][] pieces) {
       Map<Integer, int[]> mapPieces = new HashMap<>();
        for (int[] p : pieces)
            mapPieces.put(p[0], p); //bind piece by its start

        int i = 0;

        while (i < arr.length) {
            int[] p = mapPieces.get(arr[i]);
            if (p == null) return false; //not contains

            //i is contained and p starts with i
            i++;

            //check the rest of the ints in the piece (if any)
            for (int j = 1; j < p.length; j++)
                if (arr[i++] != p[j])
                    return false;
        }

        return true;
    }
}
