```java
public class Solution {

    public boolean canFormArray(int[] arr, int[][] pieces) {
        int n = arr.length;
        boolean[] dp = new boolean[n + 1];
        dp[0] = true;

        HashSet<String> set = new HashSet<>();
        for (int[] piece : pieces) {
            if (piece != null && piece.length > 0) {
                set.add(formString(piece, 0, piece.length));
            }
        }

        for (int i = 1; i <= n; i++) {
            for (int j = 0; j < i; j++) {
                if (dp[j] && set.contains(formString(arr, j, i))) {
                    dp[i] = true;
                    break;
                }
            }
        }
        return dp[n];
    }

    private String formString(int[] arr, int start, int end) {
        StringBuilder sb = new StringBuilder();
        for (int j = start; j < end; j++) {
            sb.append(arr[j]);
            sb.append(',');
        }
        return sb.toString();
    }
}
